#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define BLOCK_SIZE 512
#define POINTERS_PER_BLOCK (BLOCK_SIZE / sizeof(int))
#define MAX_FILE_SIZE ((12 + POINTERS_PER_BLOCK + POINTERS_PER_BLOCK * POINTERS_PER_BLOCK) * BLOCK_SIZE)

// i-node structure (simplified UNIX inode)
typedef struct {
 int inode_number;
 short permissions;
 short link_count;
 int uid;
 int gid;
 int size;
 int creation_time;
 int modification_time;

 // Block pointers
 int direct_blocks[12]; // 12 direct pointers
 int single_indirect; // Single indirect pointer
 int double_indirect; // Double indirect pointer

 // Status
 int is_allocated;
} Inode;

// File descriptor table entry
typedef struct {
 int inode_number;
 int current_position;
 int mode; // O_RDONLY, O_WRONLY, O_RDWR
} FileDescriptor;

// Simulated disk blocks
int disk_blocks[1000]; // 0 = free, 1 = allocated

// Function prototypes
Inode* allocate_inode(void);
int allocate_data_block(void);
int* get_file_blocks(Inode* inode, int block_num);
int write_to_file(Inode* inode, int offset, void* data, int size);
void free_inode(Inode* inode);
void display_inode(Inode* inode);

// Global inode table (simplified)
Inode* inode_table[128];
int next_inode_number = 0;

// Allocate a new inode
Inode* allocate_inode(void) {
 Inode* inode = (Inode*)malloc(sizeof(Inode));
 if (inode == NULL) return NULL;

 inode->inode_number = next_inode_number++;
 inode->permissions = 0644;
 inode->link_count = 1;
 inode->uid = 1000;
 inode->gid = 1000;
 inode->size = 0;
 inode->creation_time = time(NULL);
 inode->modification_time = time(NULL);

 // Initialize block pointers to -1 (unallocated)
 memset(inode->direct_blocks, -1, sizeof(inode->direct_blocks));
 inode->single_indirect = -1;
 inode->double_indirect = -1;
 inode->is_allocated = 1;

 inode_table[inode->inode_number] = inode;
 printf("Allocated inode %d\n", inode->inode_number);
 return inode;
}

// Allocate a data block
int allocate_data_block(void) {
 for (int i = 0; i < 1000; i++) {
 if (disk_blocks[i] == 0) {
 disk_blocks[i] = 1;
 printf("Allocated data block %d\n", i);
 return i;
 }
 }
 return -1; // No free blocks
}

// Get block number for a given logical block in file
int* get_file_blocks(Inode* inode, int block_num) {
 static int result[2]; // result[0] = block_number, result[1] = error code
 result[1] = 0;

 // Direct blocks: 0-11
 if (block_num < 12) {
 result[0] = inode->direct_blocks[block_num];
 return result;
 }

 // Single indirect blocks: 12 to 12 + POINTERS_PER_BLOCK - 1
 int single_offset = block_num - 12;
 if (single_offset < POINTERS_PER_BLOCK) {
 if (inode->single_indirect == -1) {
 result[1] = -1; // Block not allocated
 return result;
 }
 // Would read indirect block and get pointer
 result[0] = inode->single_indirect + single_offset; // Simplified
 return result;
 }

 // Double indirect blocks
 int double_offset = block_num - 12 - POINTERS_PER_BLOCK;
 if (double_offset < POINTERS_PER_BLOCK * POINTERS_PER_BLOCK) {
 if (inode->double_indirect == -1) {
 result[1] = -1;
 return result;
 }
 result[0] = inode->double_indirect + double_offset; // Simplified
 return result;
 }

 result[1] = -1; // File too large
 return result;
}

// Write data to file (simplified)
int write_to_file(Inode* inode, int offset, void* data, int size) {
 int start_block = offset / BLOCK_SIZE;
 int num_blocks = (offset + size + BLOCK_SIZE - 1) / BLOCK_SIZE;

 // Allocate blocks as needed
 for (int i = start_block; i < num_blocks; i++) {
 int* result = get_file_blocks(inode, i);
 if (result[1] == -1 || result[0] == -1) {
 // Need to allocate new block
 int new_block = allocate_data_block();
 if (new_block == -1) {
 printf("Error: No free blocks\n");
 return -1;
 }

 if (i < 12) {
 inode->direct_blocks[i] = new_block;
 } else if (inode->single_indirect == -1) {
 inode->single_indirect = allocate_data_block();
 // Store new_block in indirect block
 }
 }
 }

 inode->size = offset + size;
 inode->modification_time = time(NULL);
 printf("Wrote %d bytes to file (inode %d)\n", size, inode->inode_number);
 return size;
}

// Free an inode and all its data blocks
void free_inode(Inode* inode) {
 if (inode == NULL || !inode->is_allocated) return;

 // Free direct blocks
 for (int i = 0; i < 12; i++) {
 if (inode->direct_blocks[i] >= 0) {
 disk_blocks[inode->direct_blocks[i]] = 0;
 printf("Freed block %d\n", inode->direct_blocks[i]);
 }
 }

 // Free single indirect block
 if (inode->single_indirect >= 0) {
 disk_blocks[inode->single_indirect] = 0;
 }

 // Free double indirect blocks
 if (inode->double_indirect >= 0) {
 disk_blocks[inode->double_indirect] = 0;
 }

 inode->is_allocated = 0;
 printf("Freed inode %d\n", inode->inode_number);
}

// Display inode information
void display_inode(Inode* inode) {
 if (inode == NULL) return;

 printf("\n=== Inode %d ===\n", inode->inode_number);
 printf("Size: %d bytes\n", inode->size);
 printf("Permissions: %o\n", inode->permissions);
 printf("Direct blocks: ");
 for (int i = 0; i < 12; i++) {
 printf("%d ", inode->direct_blocks[i]);
 }
 printf("\n");
 printf("Single indirect: %d\n", inode->single_indirect);
 printf("Double indirect: %d\n", inode->double_indirect);

 // Calculate max file size
 long long max_size = (12 + POINTERS_PER_BLOCK + 
 (long long)POINTERS_PER_BLOCK * POINTERS_PER_BLOCK) * BLOCK_SIZE;
 printf("Maximum file size: %lld bytes\n", max_size);
}

int main() {
 printf("=== Indexed Allocation with i-node Simulation ===\n");
 printf("Block size: %d bytes\n", BLOCK_SIZE);
 printf("Pointers per block: %d\n", POINTERS_PER_BLOCK);

 // Create a new file
 Inode* myfile = allocate_inode();

 // Write some data to allocate blocks
 char data[1024] = "Hello, File System!";
 write_to_file(myfile, 0, data, 1024);

 display_inode(myfile);

 // Write more data to trigger indirect blocks
 printf("\n--- Writing more data to trigger indirect blocks ---\n");
 char more_data[BLOCK_SIZE * 20];
 write_to_file(myfile, 1024, more_data, sizeof(more_data));

 display_inode(myfile);

 // Cleanup
 printf("\n--- Cleaning up ---\n");
 free_inode(myfile);

 return 0;
}
